import Atividades from "./Atividades";
import { useState } from "react";
import { useParams, Link } from "react-router-dom";
import styled from "styled-components";
import { getInfos, getAtividades, setCompletion } from "../Dados/Dados";

export default function TelaAtividade() {
  const { nomeAtividade, nivel, passo } = useParams();
  const [infos, def, texto] = getInfos(nomeAtividade, nivel, passo);

  const [sound, setSound] = useState(new Audio());
  const [sel, setSel] = useState(null);
  const [showFeedback, setShowFeedback] = useState(false);

  function playAudio(elemento) {
    setSel(elemento);
    setShowFeedback(false);

    sound.pause();

    const musica = "/Audios/" + elemento.arquivo;
    const new_sound = new Audio(musica);
    new_sound.play();
    setSound(new_sound);
    console.log("playing ", musica);
  }

  function press_Prox() {
    setShowFeedback(true);
    sound.pause();
  }

  const proxButton = () => {
    if (sel == null) return <></>;
    if (sel.corr === 1 && showFeedback) {
      return (
        <Link
          to={{
            pathname: `/atividade/${nomeAtividade}/${nivel}/${Number(passo) + 1}`,
          }}
          onClick={() => setSel(null)}
        >
          <button>PrĂłximo</button>
        </Link>
      );
    } else {
      return <button onClick={press_Prox}>PrĂłximo</button>;
    }
  };

  return (
    <>
      <PaginaId>
        {nivel}.{passo}
      </PaginaId>
      <Page>
        <Header>Vamos Cirandar</Header>
        <Titulo>{nomeAtividade}</Titulo>
        <Dado>
          <Play
            name="play-circle"
            onClick={() => {
              playAudio(def);
            }}
          ></Play>{" "}
          OuĂ§a o inĂ­cio da Ciranda Cirandinha
        </Dado>
        <Pergunta>{texto}</Pergunta>
        <Alternativas>
          {infos.map((elemento) => (
            <Alternativa
              key={elemento.opcao}
              style={{
                color: elemento === sel ? "red" : showFeedback && elemento.corr ? "green" : "black",
              }}
              onClick={() => playAudio(elemento)}
            >
              {elemento.opcao}
            </Alternativa>
          ))}
        </Alternativas>
        <Navegacao>
          <Link to={{ pathname: `/atividades` }}>
            <button>Voltar</button>
          </Link>
          {proxButton()}
        </Navegacao>
      </Page>
    </>
  );
}

const PaginaId = styled.p`
  position: absolute;
  top: 10px;
  left: 10px;
  font-size: 18px;
`;

const Navegacao = styled.ul`
  width: 100%;
  padding: 20px;
  position: absolute;
  bottom: 25px;
  display: flex;
  justify-content: space-between;
`;

const Page = styled.main`
  width: 100%;
  height: 100%;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
`;

const Header = styled.h1`
  width: 100%;
  margin: 20px 0;
  text-align: center;
  color: #0070c0;
  font-size: 40px;
`;

const Titulo = styled.h2`
  width: 100%;
  margin: 15px 0;
  text-align: center;
  color: green;
  font-size: 30px;
`;

const Dado = styled.p`
  color: rgb(7, 166, 219);
  font-size: 30px;
  display: flex;
  justify-content: center;
  align-items: center;
`;

const Pergunta = styled.p`
  color: green;
  font-size: 30px;
  display: flex;
  justify-content: center;
  align-items: center;
`;

const Play = styled("ion-icon")`
  font-size: 50px;
  &:hover {
    color: green;
  }
`;

const Alternativas = styled.ul`
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: space-around;
`;

const Alternativa = styled.p`
  font-size: 50px;
  margin: 50px;
  cursor: pointer;
  &:hover {
    text-decoration: underline;
  }
`;
